{
  "hooks": {
    "SessionStart": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-start"
          }
        ]
      }
    ],
    "SessionEnd": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-end"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code user-prompt-submit"
          }
        ]
      }
    ],
    "Stop": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code stop"
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code pre-task"
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Edit",
        "hooks": [
          {
            "type": "command",
            "command": "if echo \"$CLAUDE_FILE_PATHS\" | grep -qE '(service|openai_client)\\.py'; then echo 'Revenue-critical file edited. Run: make validate'; fi"
          }
        ]
      },
      {
        "matcher": "Write",
        "hooks": [
          {
            "type": "command",
            "command": "if echo \"$CLAUDE_FILE_PATHS\" | grep -qE '(service|openai_client)\\.py'; then echo 'Revenue-critical file edited. Run: make validate'; fi"
          }
        ]
      },
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code post-task"
          }
        ]
      },
      {
        "matcher": "TodoWrite",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code post-todo"
          }
        ]
      }
    ]
  },
  "permissions": {
    "allow": [
      "Read(./api/src/**)",
      "Read(./api/tests/**)",
      "Read(./scripts/**)",
      "Read(./docs/**)",
      "Read(./.claude/**)",
      "Read(./*.pen)",
      "Read(./site/**)",
      "Bash(make validate)",
      "Bash(make test-fast)",
      "Bash(make test-unit)",
      "Bash(make format-fix)",
      "Bash(make lint)",
      "Bash(make natal)",
      "Bash(make synastry)",
      "Bash(make report-natal-dry)",
      "Bash(cd api && pytest *)",
      "Bash(python scripts/generate_report.py *)",
      "Bash(git status)",
      "Bash(git diff *)",
      "Bash(git log *)",
      "Bash(git push *)",
      "Bash(git push * --force)"
    ],
    "deny": [
      "Read(./docs/strategy/**)",
      "Read(./.entire/metadata/**)",
      "Read(./.env)",
      "Read(./.env.*)",
      "Bash(rm -rf *)",
      "Bash(ssh *)"
    ]
  }
}

